#!/usr/bin/env python3
import xml.etree.ElementTree as ET
import sys

def parse_deployment_config(path):
    tree = ET.parse(path)
    root = tree.getroot()
    config = {}
    for item in root.findall('.//setting'):
        config[item.get('name')] = item.text
    return config

if __name__ == '__main__':
    result = parse_deployment_config(sys.argv[1])
    for k, v in result.items():
        print(f'{k}={v}')
